import React, { useState } from "react";
import { drivers, loads, weekDays } from "../data/mockData";
import Icons from "./Icons";

const SHOW_DAYS_OPTIONS = [7, 14, 21];

export default function DispatchBoard() {
  const [showDays, setShowDays] = useState(7);
  const [activeTab, setActiveTab] = useState("New Load");
  const [search, setSearch] = useState("");
  const [selectedLoad, setSelectedLoad] = useState(null);

  const visibleDays = weekDays.slice(0, showDays);
  const gridCols = `repeat(${visibleDays.length}, minmax(110px, 1fr))`;

  // Get loads for a given driver and day index
  const getLoadsForDriverDay = (driverId, dayIndex) => {
    return loads.filter(
      (l) => l.driverId === driverId && l.startDay === dayIndex
    );
  };

  const tabs = ["New Load", "Delivered", "En Route"];

  return (
    <div style={{ padding: "16px 20px" }}>
      {/* Header row */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 12,
          flexWrap: "wrap",
          gap: 8,
        }}
      >
        <h1 style={{ fontSize: 16, fontWeight: 600, color: "#111827", margin: 0 }}>
          Dispatch Board
        </h1>
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
          {/* Pill tabs */}
          <div style={{ display: "flex", gap: 4 }}>
            {tabs.map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                style={{
                  padding: "4px 12px",
                  border: "1px solid",
                  borderColor: activeTab === tab ? "#3a8c5c" : "#d1d5db",
                  borderRadius: 12,
                  fontSize: 11,
                  cursor: "pointer",
                  background: activeTab === tab ? "#3a8c5c" : "#fff",
                  color: activeTab === tab ? "#fff" : "#374151",
                  whiteSpace: "nowrap",
                  fontWeight: activeTab === tab ? 500 : 400,
                  transition: "all 0.1s",
                }}
                onMouseEnter={(e) => {
                  if (activeTab !== tab) e.currentTarget.style.background = "#f3f4f6";
                }}
                onMouseLeave={(e) => {
                  if (activeTab !== tab) e.currentTarget.style.background = "#fff";
                }}
              >
                {tab}
              </button>
            ))}
          </div>

          {/* Search */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              border: "1px solid #d1d5db",
              borderRadius: 4,
              padding: "4px 8px",
              background: "#fff",
            }}
          >
            <Icons.search />
            <input
              type="text"
              placeholder="Search loads..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{
                border: "none",
                outline: "none",
                fontSize: 12,
                width: 150,
                color: "#374151",
                background: "transparent",
              }}
            />
          </div>
        </div>
      </div>

      {/* Filter row */}
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
        {[
          { label: "Search by Date", opts: ["Search by Date", "This Week", "Last Week", "This Month"] },
          { label: "Sort by: Driver's Name...", opts: ["Sort by: Driver's Name...", "Sort by: Load #", "Sort by: Status", "Sort by: Date"] },
          { label: "Filter by: All", opts: ["Filter by: All", "Filter by: Active", "Filter by: Completed", "Filter by: Cancelled"] },
          { label: "Drivers: Show All", opts: ["Drivers: Show All", "Drivers: Assigned", "Drivers: Unassigned"] },
        ].map((f, i) => (
          <select
            key={i}
            defaultValue={f.opts[0]}
            style={{
              border: "1px solid #d1d5db",
              borderRadius: 4,
              padding: "4px 8px",
              fontSize: 11,
              background: "#fff",
              color: "#374151",
              cursor: "pointer",
            }}
          >
            {f.opts.map((o) => (
              <option key={o}>{o}</option>
            ))}
          </select>
        ))}
      </div>

      {/* Board */}
      <div
        style={{
          display: "flex",
          border: "1px solid #e5e7eb",
          borderRadius: 4,
          overflow: "hidden",
          background: "#fff",
        }}
      >
        {/* Drivers column */}
        <div
          style={{
            width: 168,
            minWidth: 168,
            flexShrink: 0,
            borderRight: "1px solid #e5e7eb",
          }}
        >
          {/* Header */}
          <div
            style={{
              height: 44,
              borderBottom: "1px solid #e5e7eb",
              background: "#f9fafb",
              display: "flex",
              alignItems: "center",
              padding: "0 10px",
              fontSize: 11,
              fontWeight: 500,
              color: "#6b7280",
              letterSpacing: "0.5px",
            }}
          >
            DRIVERS
          </div>

          {/* Driver rows */}
          {drivers.map((driver) => (
            <div
              key={driver.id}
              style={{
                padding: "8px 10px",
                borderBottom: "1px solid #f3f4f6",
                minHeight: 70,
                display: "flex",
                flexDirection: "column",
                justifyContent: "center",
              }}
            >
              <div style={{ display: "flex", alignItems: "center", flexWrap: "wrap", gap: 2 }}>
                <span style={{ fontSize: 11, fontWeight: 500, color: "#374151", lineHeight: 1.3 }}>
                  {driver.name}
                </span>
                <span
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    padding: "1px 5px",
                    background: "#dbeafe",
                    color: "#1d4ed8",
                    borderRadius: 3,
                    fontSize: 9,
                    fontWeight: 600,
                  }}
                >
                  {driver.type}
                </span>
              </div>
              <div style={{ fontSize: 10, color: "#9ca3af", marginTop: 2 }}>{driver.phone}</div>
            </div>
          ))}

          {/* Unassigned row */}
          <div
            style={{
              padding: "8px 10px",
              borderBottom: "1px solid #f3f4f6",
              minHeight: 50,
              background: "#fafafa",
            }}
          >
            <span style={{ fontSize: 10, color: "#9ca3af", fontStyle: "italic" }}>
              Unassigned loads
            </span>
          </div>
        </div>

        {/* Grid area */}
        <div style={{ flex: 1, overflowX: "auto" }}>
          {/* Day headers */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: gridCols,
              borderBottom: "1px solid #e5e7eb",
              background: "#f9fafb",
            }}
          >
            {visibleDays.map((day) => (
              <div
                key={`${day.label}-${day.date}`}
                style={{
                  padding: "6px 8px",
                  textAlign: "center",
                  borderRight: "1px solid #f3f4f6",
                  fontSize: 11,
                  fontWeight: 500,
                  color: day.today ? "#3a8c5c" : "#374151",
                  background: day.today ? "rgba(58,140,92,0.06)" : day.weekend ? "#f9fafb" : "transparent",
                  height: 44,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flexDirection: "column",
                  gap: 1,
                }}
              >
                <span style={{ fontSize: 10, opacity: 0.7 }}>{day.label}</span>
                <span style={{ fontSize: 13, fontWeight: day.today ? 600 : 500 }}>{day.date}</span>
              </div>
            ))}
          </div>

          {/* Driver rows in grid */}
          {drivers.map((driver) => (
            <div
              key={driver.id}
              style={{
                display: "grid",
                gridTemplateColumns: gridCols,
                borderBottom: "1px solid #f3f4f6",
                minHeight: 70,
              }}
            >
              {visibleDays.map((day, dayIndex) => {
                const dayLoads = getLoadsForDriverDay(driver.id, dayIndex);
                const isWeekend = day.weekend;
                return (
                  <div
                    key={dayIndex}
                    style={{
                      borderRight: "1px solid #f3f4f6",
                      padding: 4,
                      background: isWeekend ? "rgba(249,250,251,0.8)" : "transparent",
                      position: "relative",
                    }}
                  >
                    {dayLoads.map((load) => {
                      const isSelected = selectedLoad === load.id;
                      return (
                        <div
                          key={load.id}
                          onClick={() => setSelectedLoad(isSelected ? null : load.id)}
                          style={{
                            background: isSelected ? "#dbeafe" : "#eff6ff",
                            border: `1px solid ${isSelected ? "#93c5fd" : "#bfdbfe"}`,
                            borderRadius: 3,
                            padding: "5px 7px",
                            cursor: "pointer",
                            minWidth: load.spanDays > 1 ? `calc(${load.spanDays * 100}% + ${(load.spanDays - 1) * 4}px)` : "auto",
                            position: load.spanDays > 1 ? "absolute" : "relative",
                            zIndex: load.spanDays > 1 ? 2 : 1,
                            left: load.spanDays > 1 ? 4 : "auto",
                            right: load.spanDays > 1 ? "auto" : "auto",
                            top: load.spanDays > 1 ? 4 : "auto",
                          }}
                        >
                          <div style={{ fontSize: 10, fontWeight: 600, color: "#1d4ed8" }}>
                            #{load.id}
                          </div>
                          <div style={{ fontSize: 10, color: "#374151", lineHeight: 1.3, marginTop: 2 }}>
                            {load.origin}
                          </div>
                          <div style={{ fontSize: 10, color: "#6b7280", lineHeight: 1.3 }}>
                            → {load.destination}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                );
              })}
            </div>
          ))}

          {/* Unassigned row */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: gridCols,
              borderBottom: "1px solid #f3f4f6",
              minHeight: 50,
            }}
          >
            {visibleDays.map((_, i) => (
              <div
                key={i}
                style={{
                  borderRight: "1px solid #f3f4f6",
                  background: "#fafafa",
                }}
              />
            ))}
          </div>

          {/* Footer: show days */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "flex-end",
              padding: "8px 10px",
              borderTop: "1px solid #e5e7eb",
              background: "#f9fafb",
              gap: 8,
              fontSize: 11,
              color: "#6b7280",
            }}
          >
            <span>Show days:</span>
            {SHOW_DAYS_OPTIONS.map((n) => (
              <button
                key={n}
                onClick={() => setShowDays(n)}
                style={{
                  padding: "3px 8px",
                  border: "1px solid #d1d5db",
                  borderRadius: 3,
                  background: showDays === n ? "#3a8c5c" : "#fff",
                  color: showDays === n ? "#fff" : "#374151",
                  borderColor: showDays === n ? "#3a8c5c" : "#d1d5db",
                  fontSize: 11,
                  cursor: "pointer",
                }}
              >
                {n}
              </button>
            ))}
          </div>
        </div>

        {/* Notes panel */}
        <div
          style={{
            width: 164,
            minWidth: 164,
            borderLeft: "1px solid #e5e7eb",
            background: "#f9fafb",
            flexShrink: 0,
          }}
        >
          {/* Notes header */}
          <div
            style={{
              height: 44,
              borderBottom: "1px solid #e5e7eb",
              display: "flex",
              alignItems: "center",
              padding: "0 10px",
              fontSize: 11,
              fontWeight: 600,
              color: "#374151",
              letterSpacing: "0.5px",
            }}
          >
            NOTES
          </div>

          {/* Notes content */}
          <div style={{ padding: 10 }}>
            <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 10 }}>
              {["+ Add note", "+ Add lumper", "View details"].map((link) => (
                <a
                  key={link}
                  href="#"
                  style={{ fontSize: 11, color: "#3b82f6", textDecoration: "none", cursor: "pointer" }}
                  onMouseEnter={(e) => (e.target.style.textDecoration = "underline")}
                  onMouseLeave={(e) => (e.target.style.textDecoration = "none")}
                >
                  {link}
                </a>
              ))}
            </div>
            <span
              style={{
                display: "inline-flex",
                alignItems: "center",
                padding: "2px 8px",
                background: "#fee2e2",
                color: "#991b1b",
                borderRadius: 3,
                fontSize: 10,
                fontWeight: 600,
              }}
            >
              INACTIVE
            </span>
          </div>

          {/* Load details if selected */}
          {selectedLoad && (() => {
            const load = loads.find((l) => l.id === selectedLoad);
            if (!load) return null;
            return (
              <div
                style={{
                  margin: "0 8px 8px",
                  padding: "8px",
                  background: "#fff",
                  border: "1px solid #e5e7eb",
                  borderRadius: 4,
                  fontSize: 11,
                }}
              >
                <div style={{ fontWeight: 600, color: "#1d4ed8", marginBottom: 4 }}>#{load.id}</div>
                <div style={{ color: "#6b7280", marginBottom: 2 }}>Miles: {load.miles}</div>
                <div style={{ color: "#6b7280", marginBottom: 2 }}>Rate: ${load.rate}</div>
                <div style={{ marginTop: 6 }}>
                  <StatusBadgeSmall status={load.status} />
                </div>
              </div>
            );
          })()}
        </div>
      </div>
    </div>
  );
}

function StatusBadgeSmall({ status }) {
  const map = {
    "In Transit": { bg: "#dbeafe", color: "#1d4ed8" },
    "Delivered": { bg: "#dcfce7", color: "#166534" },
    "En Route": { bg: "#e0e7ff", color: "#3730a3" },
    "Pending": { bg: "#f3f4f6", color: "#6b7280" },
  };
  const s = map[status] || map["Pending"];
  return (
    <span
      style={{
        padding: "2px 6px",
        borderRadius: 10,
        fontSize: 10,
        fontWeight: 500,
        background: s.bg,
        color: s.color,
      }}
    >
      {status}
    </span>
  );
}
